    ({ rows } = await query(sql, [accountId, q]));
  } catch (err) {
    return NextResponse.json({ ok: false, error: err.message, sql }, { status: 400 });
  }

  return NextResponse.json({
    ok: true,
    results: rows.map((r) => r.description),
